package weekOne;

public class Practice_Exe {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		

		        // a. Output "Hello World"
		        System.out.println("Hello World");

		        // b. Output your first name as a String literal
		        System.out.println("Hina");

		        // c. Store your first name in a String variable called name
		        String name = "Hina";
		        System.out.println(name);

		        // d. Store an address in a String variable called address
		        String address = "Station Walk, Newbridge";
		        System.out.println(address);

		        // e. Output the year the Olympics were held in Sydney
		        System.out.println(2000);

		        // f. Store the year in an int variable
		        int yearSydneyOlympics = 2000;
		        System.out.println(yearSydneyOlympics);

		        // g. Append text with name variable
		        String nameOutput = "My name is " + name;
		        System.out.println(nameOutput);

		        // h. Inline output without declaring another variable
		        System.out.println("My name is " + name);

		        // i. Append text with year variable
		        String yearSydneyOlympicsOutput = "The Sydney Olympics were held in " + yearSydneyOlympics;
		        System.out.println(yearSydneyOlympicsOutput);

		        // j. Inline output from i
		        System.out.println("The Sydney Olympics were held in " + yearSydneyOlympics);

		        // k. Declare sum and output it
		        int sum = 3 + 2;
		        System.out.println("Sum is " + sum);

		        // l. Declare two int variables and add them
		        int a = 2, b = 3;
		        sum = a + b;
		        System.out.println("Sum of " + a + " and " + b + " is " + sum);
		    }
		}

	
